from __future__ import annotations

import os
import sys
import math
import traceback
import torch
import torch.distributed as dist
import torch.multiprocessing as mp
from transformers import LlamaForCausalLM, LlamaConfig

sys.path.insert(0, '/app')
from pipeline_parallel import train_step_pipeline_afab, _partition


def make_cfg():
    return LlamaConfig(
        vocab_size=128,
        hidden_size=32,
        intermediate_size=64,
        num_hidden_layers=4,
        num_attention_heads=4,
        num_key_value_heads=4,
        max_position_embeddings=16,
        use_cache=False,
        rms_norm_eps=1e-6,
        tie_word_embeddings=False,
    )


def gen_inputs():
    torch.manual_seed(456)
    inputs = [
        torch.randint(0, 128, (2, 8), dtype=torch.long),
        torch.randint(0, 128, (3, 6), dtype=torch.long),
    ]
    targets = [
        torch.randint(0, 128, (2, 8), dtype=torch.long),
        torch.randint(0, 128, (3, 6), dtype=torch.long),
    ]
    return inputs, targets


def worker(rank, world_size, port, results):
    try:
        os.environ['MASTER_ADDR'] = '127.0.0.1'
        os.environ['MASTER_PORT'] = str(port)
        dist.init_process_group('gloo', rank=rank, world_size=world_size)
        torch.manual_seed(123)
        cfg = make_cfg()
        model = LlamaForCausalLM(cfg).to(device=torch.device('cpu'), dtype=torch.float64)
        for p in model.parameters():
            p.requires_grad_(True)
        inputs, targets = gen_inputs()
        in_list = inputs if rank == 0 else []
        tg_list = targets if rank == world_size - 1 else []
        loss = train_step_pipeline_afab(model, in_list, tg_list, torch.device('cpu'), torch.float64)

        total_layers = len(model.model.layers)
        local_start, local_end = _partition(0, total_layers, world_size, rank)
        grads = {}
        for i, layer in enumerate(model.model.layers[local_start:local_end]):
            for n, p in layer.named_parameters():
                if p.grad is not None:
                    grads[f'model.layers.{local_start + i}.{n}'] = p.grad.detach().clone()
        if rank == 0:
            p = model.model.embed_tokens.weight
            if p.grad is not None:
                grads['model.embed_tokens.weight'] = p.grad.detach().clone()
        if rank == world_size - 1:
            for n, p in model.model.norm.named_parameters():
                if p.grad is not None:
                    grads[f'model.norm.{n}'] = p.grad.detach().clone()
            for n, p in model.lm_head.named_parameters():
                if p.grad is not None:
                    grads[f'lm_head.{n}'] = p.grad.detach().clone()
        results[rank] = {'ok': True, 'loss': None if loss is None else float(loss.detach()), 'grads': grads, 'local_start': local_start, 'local_end': local_end}
        dist.barrier()
        dist.destroy_process_group()
    except Exception as e:
        tb = traceback.format_exc()
        try:
            dist.destroy_process_group()
        except Exception:
            pass
        results[rank] = {'ok': False, 'error': str(e), 'traceback': tb}


def reference():
    torch.manual_seed(123)
    cfg = make_cfg()
    model = LlamaForCausalLM(cfg).to(device=torch.device('cpu'), dtype=torch.float64)
    for p in model.parameters():
        p.requires_grad_(True)
    inputs, targets = gen_inputs()
    model.train()
    for p in model.parameters():
        if p.grad is not None:
            p.grad = None
    total_loss = 0.0
    num_mb = len(inputs)
    for mb in range(num_mb):
        out = model(input_ids=inputs[mb], labels=targets[mb])
        loss = out.loss / num_mb
        total_loss += float(loss.detach())
        loss.backward()
    grads = {}
    for n, p in model.named_parameters():
        if p.grad is not None:
            grads[n] = p.grad.detach().clone()
    return total_loss, grads


def run_world(world_size, port):
    print(f'===== variable world_size={world_size} =====', flush=True)
    mgr = mp.Manager()
    results = mgr.dict()
    ctx = mp.get_context('spawn')
    procs = [ctx.Process(target=worker, args=(r, world_size, port, results)) for r in range(world_size)]
    for p in procs:
        p.start()
    for p in procs:
        p.join(60)
    for p in procs:
        if p.is_alive():
            p.terminate()
    res = dict(results)
    for r in range(world_size):
        rr = res.get(r, {})
        if not rr.get('ok'):
            print(f'rank {r} failed:\n{rr.get("traceback", rr.get("error"))}', flush=True)
            return False
        print(f'rank {r}: layers={rr["local_start"]}:{rr["local_end"]} loss={rr["loss"]}', flush=True)
    ref_loss, ref_grads = reference()
    print(f'reference loss={ref_loss}', flush=True)
    max_abs = 0.0
    mismatches = []
    for r in range(world_size):
        for name, g in res[r]['grads'].items():
            if name not in ref_grads:
                print('missing reference grad', name, flush=True)
                return False
            ref_g = ref_grads[name]
            diff = (g - ref_g).abs().max().item()
            max_abs = max(max_abs, diff)
            if diff > 1e-6:
                mismatches.append((name, diff))
    print(f'max grad diff vs reference: {max_abs}', flush=True)
    if mismatches:
        print('mismatches:', mismatches[:20], flush=True)
        return False
    return True


def main():
    ok = True
    for ws in (1, 2):
        ok = run_world(ws, 29600 + ws) and ok
    print('VARIABLE TESTS', 'PASS' if ok else 'FAIL', flush=True)
    sys.exit(0 if ok else 1)


if __name__ == '__main__':
    main()
